const Q_ECONOMICS_1994=[{"id": "objective>Economics>1994>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basic economic problems of the society include.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">what to produce, how and for whom </div>", "<div style=\"font-family:Cambria;font-size:17px;\">how to produce and sell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scarcity, when to produce and how</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scarcity, for whom to produce and where</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The basic problems of the society are:  What, how and for whom to produce and efficiency of resource use</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>1994>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Opportunity cost is an economic concept which describes the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Monetary equivalent of the utility of a commodity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amount of time or money invested on a commodity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sacrifice made for the satisfaction of a want</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost of retaining an otimum level of production of commodities.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Opportunity cost is also known as Alternative forgone , Forgone Alternative, True or Real cost. It refers to to what you have to give up to buy what you want interms of other goods or services. <br/>  For example; Mr Ojo has #500 and he is to buy a pair of trouser and a T-shirt. If he decides to buy the T-shirt, his opportunity cost is the Pair of trouser he did not buy.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>1994>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the marginal propensity to consume is 0.80 and the investment expenditure changes from #100 million to #140 million in a given economy, find the level of equilibrium in the given economy, using the formula   K=<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">1-MPC</span> (K=Multiplier; MPC = Marginal Propensity to Consume)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#20 million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#40 million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#80 million</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#200 million</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Investment expenditure changes from #100 million to #140 million <br/> ∆I =  140 - 100 <br/> = #40million <br/>  <br/> First, find K and it is given as : K = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">1-MPC</span> <br/>  <br/>  K = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> 1 - 0.8</span> <br/>  <br/> K = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">0.2</span> <br/>  <br/> K = 5 <br/>  <br/> The level of National Income ( Y ): K =<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">∆Y</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> ∆I</span>  <br/>  <br/> ∆Y = K  x ∆I <br/> ∆Y  = 5 x 40 <br/> ∆Y = #200million <br/>   </div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : THE CONCEPT OF MULTIPLIER"}, {"id": "objective>Economics>1994>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The circular flow of income defines the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Relationship between ends and means in the economic system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allocation of income to various members of the household</div>", "<div style=\"font-family:Cambria;font-size:17px;\">flow of goods, services and money among the various macro-sectors of the economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">micro-economic relationships in economic analysis</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The circular flow of income means the continuous flow of production of goods and services, income, and expenditure in an economy. It shows the redistribution of income in a circular manner between the business firms and households.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>1994>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The necessity of choice is due to the fact that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">human wants are insatiable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumers like to maximize satisfaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">resources are abundant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer are selective</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Utimately, Economics is the study of choice and scarcity. Scarcity simply means limited resources and human wants are unlimited and the resources used in satisfying humans are limited.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>1994>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> The graph above represents a production function. At which of the points does diminishing returns set in?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">L</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dimishing returns set in at point K, at the point the graph falls due to additional variable factor.</div>", "topic": "THEORY OF PRODUCTION (2) : LAWS OF PRODUCTION"}, {"id": "objective>Economics>1994>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a mixed economy, decisions to produce are taken by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">men and women acting in their own best interest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the government acting in the interest of the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the market women, the labour unions and the employers' association </div>", "<div style=\"font-family:Cambria;font-size:17px;\">private individuals, organizations and the government </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mixed economy system is an economic system whereby the means of production of the country are controlled by a private individual and the government ( state) which lead to economic growth and development.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>1994>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Every economy requires an accurate census because it assists in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">solving inflation problem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">providing a sound framework for policy formulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stimulating economic activities in the national economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solving unemployment problem</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An accurate census is a crucial feature of a national statistical system, providing baseline data and benchmarks for other collection systems.</div>", "topic": "POPULATION : INTRODUCTION"}, {"id": "objective>Economics>1994>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The population of country X in 1990 was 35 million. The births were 450,000 while it recorded 210,000 deaths. If in the same year , its immigrants were 20,000 and 10,000 of its citizens left the country, calculate the total population of the country at the end of 1990</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">24,250,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">23,350,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">34,750,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">35,250,000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The total population of a country at the end of a period can be calculated by adding the initial population, births, and immigrants, then subtracting the deaths and emigrants. In this case, the calculation would be: 35,000,000 (initial population) + 450,000 (births) + 20,000 (immigrants) - 210,000 (deaths) - 10,000 (emigrants) = 35,250,000. Therefore, the total population of country X at the end of 1990 was 35,250,000.</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>1994>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the actual population in a country is less than the optimum population, then </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it is desirable to have a larger population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is necessary to have an improved technology to sustain the population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is desirable to have a smaller population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the available resources are inadequate to sustain the population</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the population of a country is below the optimum i.e below what it ought to be, then the country is said to be under-populated. Therefore, there is a need to increase population in order to tap the available resources.</div>", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION"}, {"id": "objective>Economics>1994>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Unemployment can be reduced by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">restricting the productive base of the economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adopting capital-intensive techniques of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adopting labour-intensive techniques of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adopting a mixture of labour and capital-intensive techniques of production</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Labour intensive techniques method of production involves the use of labour ( humans) to produce goods. Unemployment can be reduced by using labour ( workers).</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR"}, {"id": "objective>Economics>1994>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> Production possibility curve of country Y <br/>  <br/> If the economy of the country is operating at X, the implication is that   </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The productive capacity is being fully utilized </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the productive capacity is not being fully utilized </div>", "<div style=\"font-family:Cambria;font-size:17px;\">too little of consumer goods is being produced</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is a disequilibrium between the production of capital and consumer goods</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Any point inside the PPC indicate that the resources are not fully utilized, technologically inefficient or there is widespread unemployment.</div>", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE"}, {"id": "objective>Economics>1994>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the total product (TP) is at maximum point, the Marginal Product (MP) and the average product (AP) respectively are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zero and decreasing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing and zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">negative and decreasing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">both at their maximum</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When TP is at maximum, MP is Zero and AP is decreasing and when TP falls, MP falls below the graph i.e negative.</div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>1994>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the long run, all production factors are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fixed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">semi-fixed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">variable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">semi-variable</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Long run is a period of time in which all factors are completely variable. Hence, no fixed factor. In the long run, the firm has enough time for expansion.</div>", "topic": "THEORY OF PRODUCTION (1) : SCALE OF PRODUCTION"}, {"id": "objective>Economics>1994>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A company's expenditure on raw materials is regarded as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">explicit cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">implicit cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prime cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average cost</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Explicit costs are the payments to outside suppliers of inputs. The costs are made during the course of production e.g wages and salaries, advertisement, paying for transport, raw materials. It is also known as Accountant Cost.</div>", "topic": "THE CONCEPT OF COST & REVENUE : EXPLICIT AND IMPLICIT COSTS"}, {"id": "objective>Economics>1994>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basic relationship between the cost of production and the market price of any commodity in the market short run is that the market price</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Always reflects the cost of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reflects the variable, but not the fixed cost of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">does not rise above variable costs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is determined by the cost of production and the current rate of inflation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The market price of a commodity in the short run is determined by the cost of production and the current rate of inflation. The cost of production includes both fixed and variable costs, while inflation affects the purchasing power of money, which in turn affects the market price. Therefore, the market price reflects both these factors.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>1994>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A firm determines its profits when it studies its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marginal cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average cost relative to price in the market</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A firm determines its profits by studying its total cost. The total cost is the sum of all costs a company incurs in producing goods or services. This includes fixed costs (costs that do not change with the level of output) and variable costs (costs that change with the level of output). By comparing the total cost with the total revenue, a firm can determine its profit or loss.</div>", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION"}, {"id": "objective>Economics>1994>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the supply of labour in a factory while other things remain equal will lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in the wage rate and an increase in the number of people employed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the wage rate and a decrease in employment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the wage rate and decrease in employment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the wage rate and an increase in employment</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the law of supply and demand, if the supply of labor increases while other factors remain constant, it will lead to a decrease in the wage rate and an increase in employment. This is because the increased supply of labor creates a surplus in the labor market, which puts downward pressure on wages. At the same time, the lower wage rate makes it more affordable for firms to hire more workers, leading to an increase in employment. None of the other options correctly describe this relationship.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR"}, {"id": "objective>Economics>1994>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A demand which is positively related to price is true of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">normal goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">giffen goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ostentatious goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital goods</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A demand which is positively related to price is true of Giffen goods. Giffen goods are a type of inferior good where the demand increases as the price increases, contrary to the law of demand. This happens because the income effect of a price increase dominates the substitution effect. In other words, when the price of a Giffen good increases, consumers feel poorer and consume more of the good, even though it's more expensive.</div>", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND"}, {"id": "objective>Economics>1994>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Price in (#)</td><td style=\"border:1px solid black;text-align:center;\"> Quantity Demanded</td><td style=\"border:1px solid black;text-align:center;\"> Quantity Supplied</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">10</td><td style=\"border:1px solid black;text-align:center;\"> 50</td><td style=\"border:1px solid black;text-align:center;\"> 450</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">20</td><td style=\"border:1px solid black;text-align:center;\"> 150</td><td style=\"border:1px solid black;text-align:center;\"> 350</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">30</td><td style=\"border:1px solid black;text-align:center;\"> 250</td><td style=\"border:1px solid black;text-align:center;\"> 250</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">40</td><td style=\"border:1px solid black;text-align:center;\"> 350</td><td style=\"border:1px solid black;text-align:center;\"> 100</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">50</td><td style=\"border:1px solid black;text-align:center;\"> 450</td><td style=\"border:1px solid black;text-align:center;\"> 50</td></tr></table></div> <br/>  <br/> What is the equilibrium quantity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250</div>", "<div style=\"font-family:Cambria;font-size:17px;\">350</div>", "<div style=\"font-family:Cambria;font-size:17px;\">450</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium quantity is the quantity at which the quantity demanded equals the quantity supplied. From the table, we can see that the quantity demanded equals the quantity supplied at a price of 30. Therefore, the equilibrium quantity is 250.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>1994>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Price in (#)</td><td style=\"border:1px solid black;text-align:center;\"> Quantity Demanded</td><td style=\"border:1px solid black;text-align:center;\"> Quantity Supplied</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">10</td><td style=\"border:1px solid black;text-align:center;\"> 50</td><td style=\"border:1px solid black;text-align:center;\"> 450</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">20</td><td style=\"border:1px solid black;text-align:center;\"> 150</td><td style=\"border:1px solid black;text-align:center;\"> 350</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">30</td><td style=\"border:1px solid black;text-align:center;\"> 250</td><td style=\"border:1px solid black;text-align:center;\"> 250</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">40</td><td style=\"border:1px solid black;text-align:center;\"> 350</td><td style=\"border:1px solid black;text-align:center;\"> 100</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">50</td><td style=\"border:1px solid black;text-align:center;\"> 450</td><td style=\"border:1px solid black;text-align:center;\"> 50</td></tr></table></div> <br/> Above the equilibrium point, a further rise in price tends to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase demand and restrict supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">restrict demand and restrict supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase demand and decrease supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease demand and increase supply</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium point in a supply and demand graph is the point where the quantity demanded equals the quantity supplied. Above this point, if the price increases, the quantity demanded decreases (as people are less willing to buy at higher prices) and the quantity supplied increases (as suppliers are more willing to supply at higher prices). However, in the given table, as the price increases above the equilibrium point (30), the quantity demanded continues to increase and the quantity supplied decreases. This is contrary to the general economic theory, but it's what the data shows. Therefore, the correct answer is 'restrict demand and restrict supply', because both quantity demanded and quantity supplied decrease as price increases above the equilibrium point.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>1994>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Price (#)</td><td style=\"border:1px solid black;text-align:center;\">Quantity sold</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">15</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">16</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">17</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">18</td></tr></table></div> <br/>  <br/> From the table above, marginal revenue is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#10</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marginal revenue = ∆TR/∆Q <br/>  <br/> Note that : TR = price x quantity <br/> 5 x15 = 75 <br/> 5 x 16 = 80 <br/> 5  x17 = 85 <br/> 5 x 18 = 90 <br/>  <br/> MR = 80 - 75 = 5 and so on.</div>", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE"}, {"id": "objective>Economics>1994>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Elasticity of demand  is an effective tool in the hands of a producer in that it enables him</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">raise his profits and lower his costs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">discourage buyers from cheating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">determine what he will produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">set his price to maximize his profit</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Elasticity helps producer to set his price to his maximum advantage. If the elasticity is elastic, he will reduce the price and if the elasticity is inelastic, he will increase his price in order to earn higher revenue</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>1994>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cross elasticity of demand can be mathematically expressed as the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">percentage change in quantity of commodity X / percentage change in quantity of commodity Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">percentage change in quantity of demanded / percentage change in price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">percentage change in quantity of demanded of commodity X / percentage change in price of commodity Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">percentage change in quantity of demanded / percentage change in income </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cross elasticity of demand is the relation between percentage change in the quantity demanded for a good to the percentage change in the price of a related good. It is always beteen good A(x) and B(Y) and it is calculated as: <br/>  <br/> <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">Percentage change in quantity demanded of (B)X</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> Percentage change in Price of(A) Y</span></div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>1994>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basic idea behind brand differentiation under an imperfect market arrangement is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stimulate demand for rival products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">create demand for the particular product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enable the product penetrate the market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enable the product to compete with others</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Product differentiation plays an inportant role for firms that are in monopolistic competition.With the help of product differentiation, firms in monopolistic competition can have some market over the price of their product.</div>", "topic": "MARKET STRUCTURE : MONOPOLISTIC COMPETITION"}, {"id": "objective>Economics>1994>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the long run, a firm in a perfectly competitive market will make </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">normal profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">abnormal profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">no profit</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the long run, the firm will be making normal profit. Abnormal profit will be completely wiped off since new firms will enter the industry i.e will have economic profits of zero.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>1994>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Output restriction, fixing of prices, creating obstacles to free entry into the market are features of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pure monopoly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfect competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monopolistic competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monopsonist competition</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monopoly is a price maker i.e he can set his price or output but not at the same time. In a monoploy market, there is no free entry and exit and also there is preferential treatment.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>1994>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major shortcoming of the sole proprietorship form of business is lack of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">working capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">patronage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">continuity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the event of death of the owner, the business may also die with him, especially when there is no successor to take over from him. Another disadvantages of sole proprietorship is that there is unlimited liability.</div>", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP"}, {"id": "objective>Economics>1994>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the event of liquidation of a private limited liability company, the shareholders' liability is limited in their total</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">income from all sources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">family assets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">collateral offered for banks loans </div>", "<div style=\"font-family:Cambria;font-size:17px;\">investement in the company</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a company limited liability by shares, the liability of the shareholders for company debts is limited to the capital originally invested in the business i.e the nominal value of the shares they own.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>1994>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major factor that causes fluctuations in the supply of agricultural produce is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pests</div>", "<div style=\"font-family:Cambria;font-size:17px;\">weather variations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rural-urban migration</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Unpredictable and unfavourable climate like high temperature, low rainfall generally discourage serious farming activities.</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>1994>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The system of agricultural practice which involves hunting, gathering and growing of food crops for family consumption only is described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pleasant agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plantation agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">co-operative farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subsistence farming</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Subsistence farming also known as peasant farming is defined as the type of agriculture which is concerned with the production of food for the farmer and his family.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>1994>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the term used to describe a policy aimed at promoting the local production of goods which are usually imported?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">deregulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">import substitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tarrif reduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">backward integration</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Import substitution strategy involves delibrate attempt by government aimed at encouraging the growth of industries within the country which produce goods and services which would otherwise have been imported.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INDIGENISATION & NATIONALISATION"}, {"id": "objective>Economics>1994>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Labour intensive strategy of industrialization emphasizes the use of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">steam energy in the process of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manual method of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">synthentic raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydro-electric power</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Labour intensive strategy of industrialization emphasizes the use of more labour in relation to capital or in other words, it refers to the use of manual method of production. This strategy is often used in developing countries where labour is abundant and capital is scarce.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>1994>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Petroleum is the mainstay of the Nigerian economy because it is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">main foreign exchange earner</div>", "<div style=\"font-family:Cambria;font-size:17px;\">greatest employer of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">greatest contributor to the growth of agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">source of high income for its workers</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Petroleum is considered the mainstay of the Nigerian economy because it is the main foreign exchange earner. The revenue generated from the export of petroleum significantly contributes to the country's GDP and finances a large portion of the government's budget.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>1994>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An indigenous company wholly owned by the Federal government of Nigeria which currently engages in prospecting for oil is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian National Oil company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Peak petroleum Industries Nigeria limited</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria Exploration and Production Company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Nigeria National Petroleum Corporation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigeria National Petroleum Corporation (NNPC) was assigned the responsibility for the exploration, production and refining of petroleum, as well as the distribution and foreign marketing of crude oil and petroleum products.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : NNPC"}, {"id": "objective>Economics>1994>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in both the legal reserve ratio and discount rate has the effect of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing the quantity of money in circulation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing the quantity of money in circulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the value of money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing the value of money</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Discount rate also known as Bank rate is the minimum rate of interest charged by the central bank for discounting bill of exchange. By lowering or raising the rate, the central bank can control the activitties of the commercial banks. When the rate increases, loan to the public reduces and vice versa.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>1994>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Inflation in the Nigeria economy may be fuelled by increase in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the dollar rise of crude oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the sale of company shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government expenditure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sale of government bond</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in government spending(expenditure) is one of the factors that economist say can drive inflation.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>1994>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Gresham's law in economics shows that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">good money drives out bad money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bad money drives out good money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the value of money varies inversely with the price level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gold must be available to maintain the value of paper money</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gresham's law is a monetary principle stating that \" Bad money drives out good money out of circulation\". It is primary used for consideration and application in currency markets.</div>", "topic": "MONEY : VALUE OF MONEY"}, {"id": "objective>Economics>1994>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Monetary policy aimed at reducing demand-pull inflation in the country may be carried out through </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase in taxation of private companies, public corporations and private individuals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in cash reserve ratio of commercial banks and the sale of government securities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in government expenditure on education</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct price control in the market place.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monetary policy is the policy adopted by the monetary authority of a country that controls either the interest rate payable on very short-term borrowing or the money supply, often targeting inflation or the interest rate to ensure price stability and general trust in the currency. Demand-pull inflation is asserted to arise when demand in an economy outpaces supply. It involves inflation rising as real gross domestic product rises and unemployment falls. This is commonly described as 'too much money chasing too few goods'. To reduce demand-pull inflation, the monetary authority can increase the cash reserve ratio of commercial banks and sell government securities. Increasing the cash reserve ratio reduces the amount of money banks can lend, thereby reducing the money supply in the economy. Selling government securities also reduces the money supply because when individuals and businesses buy these securities, they essentially give their money to the government, reducing the amount of money in circulation.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>1994>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Progressive tax structure is designed to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">take more from the income of the poor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">take more from the income of the rich</div>", "<div style=\"font-family:Cambria;font-size:17px;\">take equal proportion of income from both the rich and the poor </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the problems emanating from tax imposition</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A tax is progressive if the tax rate increases as the income increases e.g personal income tax, PAYE. It varies direclty with the level of income i.e the higher the income, the higher the tax paid.</div>", "topic": "PUBLIC FINANCE : PRINCIPLE OF TAXATION"}, {"id": "objective>Economics>1994>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Taxes and government expenditures are instruments of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">monetary policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tax policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fiscal policy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Taxes and government expenditures are instruments of fiscal policy. Fiscal policy refers to the use of government revenue collection (taxation) and expenditure (spending) to influence a country's economy. The other options do not accurately represent the use of taxes and government expenditures.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>1994>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The national income of a country indicates that the gross national income was #17,700 million and gross domestic product was #16,800 million. The difference of #900 million represents</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debt repayments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">investments abroad</div>", "<div style=\"font-family:Cambria;font-size:17px;\">net income from abroad</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital consumption</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gross domestic product is the total value of goods and services produced in a country excluding net income from abroad while Gross national product is the total value of goods and services produced in a country including net income from abroad.  <br/>  <br/> Therefore, the difference between the GDP and GNP is net income from abroad.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>1994>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If national income rises by 6% and population rises by 3%, per capita income will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rise by 6 percent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall by 3 percent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall by 6 percent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rise by 3 percent</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Per capita income is calculated by dividing the national income by the total population. If the national income rises by 6% and the population rises by 3%, the per capita income will rise, but not by the full 6%. The difference between the percentage increase in national income and the percentage increase in population gives the percentage increase in per capita income. Therefore, the per capita income will rise by 3%.</div>", "topic": "NATIONAL INCOME : DIFFERENCE BETWEEN STANDARD OF LIVING & COST OF LIVING"}, {"id": "objective>Economics>1994>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the ways by which the government can speed up economic development is through the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase in consumption pattern of the people </div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouragement of savings, investment and equitable distribution of goods and services </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in the rate of population growth so as to ensure that the country has a large labour force</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouragement of importation of raw materials to produce consumer goods</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ways by which the government can speed up economic development is through the encouragement of savings, investment and equitable distribution of goods and services  <br/> </div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>1994>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A sustained increase in the production of goods and services in a country is called economic </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diversification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">planning</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A sustained increase in the production of goods and services in a country is referred to as economic growth. Economic growth is a measure of the increase in the amount of goods and services produced by an economy over time. It is conventionally measured as the percent rate of increase in real gross domestic product, or GDP.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>1994>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the techniques for rectifying a deficit balance of payment is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">import promotion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">devaluation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">physical intervention</div>", "<div style=\"font-family:Cambria;font-size:17px;\">borrowing from abroad</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Devaluation helps to improve the balance of payment by reducing imports and increasing exports. It makes currency cheaper as the prices of goods produced locally fall.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>1994>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main objective of the Economic Community of West african States is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">establish a west african development bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">create a west african army</div>", "<div style=\"font-family:Cambria;font-size:17px;\">introduce a common currency for the sub-region </div>", "<div style=\"font-family:Cambria;font-size:17px;\">promote the free movement of persons , goods and services within the sub-region</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">ECOWAS foster closer relations i.e by encouraging free movement of citizens, goods and services and also promote co-operation and development in all fields of economic activity.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF"}, {"id": "objective>Economics>1994>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In international trade, shipping and other freight charges are treated as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">invisible items</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unilateral transfers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital transactions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">autonomous capital transactions</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In international trade, shipping and other freight charges are treated as invisible items. Invisible tarde include service( receipts and payments arising from activities such as customer services or shipping); income from foreign investment in the form of interest, profits, and dividends, private or government transfers or monies from one country to another etc.</div>", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE"}, {"id": "objective>Economics>1994>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A situation in which a commodity is sold abroad below its cost of production in the home country is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dumping </div>", "<div style=\"font-family:Cambria;font-size:17px;\">counter trade </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bilateral trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trade liberalization</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dumping is a term used in the context of international trade. It's when a country or company exports a product at a price that is lower in the foreign importing market than the price in the exporter's domestic market. The reason they might do this is to increase market share in the foreign market or to offload excess domestic supply.</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>1994>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The borrowing rights of a member country of the international monetary fund are determined by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the seriousness of the country's economic problems</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its balance of payments position</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its quota to the fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the size of its gold reserve</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The money the IMF loans to its members on its best-or-on concessional -terms comes from member countries, mainly through their payment of quotas.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC"}];
